// ...existing code...
<template>
  <div>
    <nav class="login-navbar">
      <div class="flex items-center">
        <span class="logo"><i class="fas fa-graduation-cap"></i> XX考试系统</span>
        <span class="title">用户登录</span>
      </div>
      <div class="flex items-center">
        <span class="text-gray-600"><i class="fas fa-user"></i> 未登录</span>
      </div>
    </nav>
    <div class="login-container">
      <h2>欢迎登录</h2>
      <form @submit.prevent="login">
        <div class="input-group">
          <label for="username">用户名</label>
          <input type="text" id="username" v-model="username" placeholder="请输入用户名" required>
        </div>
        <div class="input-group">
          <label for="password">密码</label>
          <input type="password" id="password" v-model="password" placeholder="请输入密码" required>
        </div>
        <div v-if="errorMsg" class="error-msg">{{ errorMsg }}</div>
        <button type="submit" class="btn btn-primary w-100 mb-2" style="font-size:1.1rem; padding:0.9rem 0;">登录</button>
        <button class="register-btn btn btn-success w-100" type="button" style="font-size:1.1rem; padding:0.9rem 0;" @click="goRegister">注册</button>
      </form>
    </div>
  </div>
</template>

<script>
import axios from 'axios'
export default {
  data() {
    return {
      username: '',
      password: '',
      errorMsg: ''
    }
  },
  methods: {
    async login() {
      this.errorMsg = ''
      try {
        const res = await axios.post('/api/token', {
          username: this.username,
          password: this.password
        })
        if (res.data.access) {
          localStorage.setItem('token', res.data.access)
          this.$router.push('/index')
        } else {
          this.errorMsg = '登录失败'
        }
      } catch (e) {
        this.errorMsg = e.response?.data?.detail || '用户名或密码错误'
      }
    },
    goRegister() {
      this.$router.push('/register')
    }
  }
}
</script>

<style scoped>
/* 可保留原有样式 */
</style>
