import Vue from 'vue';
import Router from 'vue-router';
import Home from '../views/Home.vue';
import Login from '../views/Login.vue';
import Register from '../views/Register.vue';
import IndexStu from '../views/IndexStu.vue';
import IndexTeacher from '../views/IndexTeacher.vue';
import IndexAdmin from '../views/IndexAdmin.vue';
import Exam from '../views/Exam.vue';
import ExamManage from '../views/ExamManage.vue';
import ExamForm from '../views/ExamForm.vue';
import QuestionManage from '../views/QuestionManage.vue';
import QuestionForm from '../views/QuestionForm.vue';
import ScoreQuery from '../views/ScoreQuery.vue';

Vue.use(Router);

export default new Router({
  mode: 'history',
  routes: [
    { path: '/', component: Home },
    { path: '/login', component: Login },
    { path: '/register', component: Register },
    { path: '/student', component: IndexStu },
    { path: '/teacher', component: IndexTeacher },
    { path: '/admin', component: IndexAdmin },
    { path: '/exam', component: Exam },
    { path: '/exam-manage', component: ExamManage },
    { path: '/exam-add', component: ExamForm },
    { path: '/exam-edit/:examId', component: ExamForm, props: true },
    { path: '/question-manage', component: QuestionManage },
    { path: '/question-add', component: QuestionForm },
    { path: '/question-edit/:questionId', component: QuestionForm, props: true },
    { path: '/score', component: ScoreQuery }
  ]
});

import { createRouter, createWebHistory } from 'vue-router';
import Home from '../views/Home.vue';
import Login from '../views/Login.vue';
import Register from '../views/Register.vue';
import IndexStu from '../views/IndexStu.vue';
import IndexTeacher from '../views/IndexTeacher.vue';
import IndexAdmin from '../views/IndexAdmin.vue';
import Exam from '../views/Exam.vue';
import ExamManage from '../views/ExamManage.vue';
import ExamForm from '../views/ExamForm.vue';
import QuestionManage from '../views/QuestionManage.vue';
import QuestionForm from '../views/QuestionForm.vue';
import ScoreQuery from '../views/ScoreQuery.vue';

const routes = [
  { path: '/', component: Home },
  { path: '/login', component: Login },
  { path: '/register', component: Register },
  { path: '/student', component: IndexStu },
  { path: '/teacher', component: IndexTeacher },
  { path: '/admin', component: IndexAdmin },
  { path: '/exam', component: Exam },
  { path: '/exam-manage', component: ExamManage },
  { path: '/exam-add', component: ExamForm },
  { path: '/exam-edit/:examId', component: ExamForm, props: true },
  { path: '/question-manage', component: QuestionManage },
  { path: '/question-add', component: QuestionForm },
  { path: '/question-edit/:questionId', component: QuestionForm, props: true },
  { path: '/score', component: ScoreQuery }
];

const router = createRouter({
  history: createWebHistory(),
  routes
});

export default router;

const { defineConfig } = require('@vue/cli-service')
module.exports = defineConfig({
  // transpileDependencies: [] // 如果没有特殊依赖可直接删除
});

